prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> 

prefix : <http://cmt#> 

SELECT (COUNT(*) AS ?cnt) 

	WHERE {?c rdf:type :Conference; 

		:hasConferenceMember ?p . 

		?p rdf:type :Person }

prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> 

prefix : <http://cmt#> 

SELECT (COUNT(*) AS ?cnt) 

	WHERE {?c rdf:type :ProgramCommittee; 

		:hasProgramCommitteeMember ?p . 

		?p rdf:type :Person }
